class Solution {
public:
    long long countWays(string s) {
        const long long MOD = 1000000007;

        long long n = s.size();
        s = " " + s; // Add leading space for 1-based indexing

        vector<vector<pair<long long, long long>>> d(n + 1);
        d[1] = {{1, 1}}; // Initialize first character

        // Fill ranges for each character
        for (long long i = 2; i <= n; i++) {
            d[i] = {{i, i}}; 
            if (s[i] == s[i - 1]) {
                d[i].push_back({i - 1, i});
            }
            for (auto j : d[i - 1]) {
                if (s[j.first - 1] == s[i]) {
                    d[i].push_back({j.first - 1, i});
                }
            }
        }

        // DP array to count ways
        vector<long long> f(n + 1, 0);
        f[0] = 1; // Base case

        for (long long i = 1; i <= n; i++) {
            for (auto j : d[i]) {
                f[i] += f[j.first - 1];
                f[i] %= MOD;
            }
        }

        return f[n];
    }
};

