#define MOD 1000000007LL

// Function to build ranges d[i]
void build_ranges(char *a, int n, int **d, int *dsz) {
    d[1][dsz[1]++] = 1;

    for (int i = 2; i <= n; ++i) {
        // always add (i,i) -> start = i
        d[i][dsz[i]++] = i;

        // if s[i] == s[i-1] add (i-1, i) -> start = i-1
        if (a[i] == a[i - 1]) {
            d[i][dsz[i]++] = i - 1;
        }

        // for each tuple in d[i-1] with start = st
        for (int k = 0; k < dsz[i - 1]; ++k) {
            int st = d[i - 1][k];
            int prev_index = st - 1;
            if (prev_index >= 0 && a[prev_index] == a[i]) {
                d[i][dsz[i]++] = prev_index;
            }
        }
    }
}

// Function to compute number of ways using DP
long long count_ways(char *s) {
    int n = (int)strlen(s);
    if (n == 0) return 0;

    // make 1-based array (a[0] = ' ')
    char *a = (char *)malloc((n + 2) * sizeof(char));
    a[0] = ' ';
    for (int i = 1; i <= n; ++i) a[i] = s[i - 1];

    // allocate ranges
    int **d = (int **)malloc((n + 2) * sizeof(int *));
    int *dsz = (int *)malloc((n + 2) * sizeof(int));
    for (int i = 0; i <= n; ++i) {
        d[i] = (int *)malloc((n + 2) * sizeof(int));
        dsz[i] = 0;
    }

    // build ranges
    build_ranges(a, n, d, dsz);

    // DP
    long long *f = (long long *)calloc((n + 2), sizeof(long long));
    f[0] = 1;
    for (int i = 1; i <= n; ++i) {
        long long sum = 0;
        for (int k = 0; k < dsz[i]; ++k) {
            int st = d[i][k];
            int idx = st - 1;
            if (idx >= 0 && idx <= n) {
                sum += f[idx];
                if (sum >= (1LL << 62)) sum %= MOD; // avoid overflow
            }
        }
        f[i] = sum % MOD;
    }

    long long ans = f[n];

    // cleanup
    for (int i = 0; i <= n; ++i) free(d[i]);
    free(d);
    free(dsz);
    free(f);
    free(a);

    return ans;
}

