class Solution {
    static final int MOD = 1000000007;

    /**
     * Count ways to form the string using the same algorithm you provided.
     * Returns 0 for empty input (consistent with the C refactor behavior).
     */
    public long countWays(String input) {
        if (input == null) return 0;
        int n = input.length();
        if (n == 0) return 0;

        // add leading space to make string 1-indexed
        String s = " " + input; // length is n+1, valid indices [0..n]

        // d[i] will hold list of int[]{start, end} pairs (we only use start)
        List<List<int[]>> d = new ArrayList<>(n + 1);
        for (int i = 0; i <= n; i++) d.add(new ArrayList<>());

        // initialize d[1] if n >= 1
        d.get(1).add(new int[]{1, 1});

        // build ranges
        for (int i = 2; i <= n; i++) {
            d.get(i).add(new int[]{i, i});
            if (s.charAt(i) == s.charAt(i - 1)) {
                d.get(i).add(new int[]{i - 1, i});
            }
            for (int[] prev : d.get(i - 1)) {
                int start = prev[0];
                // check s[start-1] == s[i]
                if (s.charAt(start - 1) == s.charAt(i)) {
                    d.get(i).add(new int[]{start - 1, i});
                }
            }
        }

        // DP array
        long[] f = new long[n + 1];
        f[0] = 1;

        for (int i = 1; i <= n; i++) {
            long sum = 0;
            for (int[] pair : d.get(i)) {
                int start = pair[0];
                int idx = start - 1;
                if (idx >= 0 && idx <= n) {
                    sum += f[idx];
                    if (sum >= (1L << 62)) sum %= MOD; // occasional reduction
                }
            }
            f[i] = sum % MOD;
        }

        return f[n];
    }
}

