function countWays(inputStr) {
  const MOD = 1000000007n; // BigInt modulo
  let s = (inputStr === null || inputStr === undefined) ? "" : inputStr.trim();
  let n = s.length;
  // handle empty string: by original DP logic f[0] = 1 => result 1
  if (n === 0) return "1";

  // make 1-based indexing (prefix space)
  s = " " + s;
  // d[i] = array of [L, R] pairs (L and R are numbers)
  const d = Array.from({ length: n + 1 }, () => []);
  // Use a set-per-index to avoid duplicate ranges like [a,b] being pushed twice
  const seen = Array.from({ length: n + 1 }, () => new Set());

  // initialize for i = 1
  d[1].push([1, 1]);
  seen[1].add("1,1");

  for (let i = 2; i <= n; i++) {
    // always can have single char range [i, i]
    const keySingle = `${i},${i}`;
    if (!seen[i].has(keySingle)) {
      d[i].push([i, i]);
      seen[i].add(keySingle);
    }

    // If same as previous char, add [i-1, i]
    if (s[i] === s[i - 1]) {
      const keyPrev = `${i - 1},${i}`;
      if (!seen[i].has(keyPrev)) {
        d[i].push([i - 1, i]);
        seen[i].add(keyPrev);
      }
    }

    // Extend previous ranges where applicable
    for (const j of d[i - 1]) {
      const Lprev = j[0]; // j = [Lprev, Rprev], Rprev should be i-1
      const candidateL = Lprev - 1;
      if (candidateL >= 1 && s[candidateL] === s[i]) {
        const key = `${candidateL},${i}`;
        if (!seen[i].has(key)) {
          d[i].push([candidateL, i]);
          seen[i].add(key);
        }
      }
    }
  }

  // DP f array (BigInt)
  const f = Array(n + 1).fill(0n);
  f[0] = 1n;

  for (let i = 1; i <= n; i++) {
    let sum = 0n;
    for (const range of d[i]) {
      const L = range[0];
      sum += f[L - 1];
      if (sum >= 8n * MOD) sum %= MOD; // occasional reduction to keep numbers small
    }
    f[i] = sum % MOD;
  }

  return f[n].toString(); // string for printing
}
